public class Main {
    static int add(int a, int b) {
        return a + b;
    }

    public static void main(String[] args) {
        int sum = add(3, 4);
        System.out.println(sum);
    }
}

static int add(int a, int b) {
    return a + b;
}

// add(3, 4)      -> works
// add(3.5, 4)    -> does not compile: 3.5 is a double, not an int
// add("3", 4)     -> does not compile: "3" is a String, not an int

public class Main {
    static void tryToChange(int x) {
        x = 100;
    }

    public static void main(String[] args) {
        int number = 5;
        tryToChange(number);
        System.out.println(number);
    }
}

public class Main {
    static double average(int a, int b, int c) {
        return (a + b + c) / 3.0;
    }

    public static void main(String[] args) {
        double result = average(10, 20, 30);
        System.out.println("Average: " + result);
    }
}

